-- Ken's Hardened V2 Fix

local b64_0xlll11l = {}
local char_0xlI1IIl='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xll1lII=1,#char_0xlI1IIl do b64_0xlll11l[char_0xlI1IIl:sub(i_0xll1lII,i_0xll1lII)] = i_0xll1lII - 1 end

function b64_0xlll11l.dec_0xIIllII(d_0xll1lI1)
    d_0xll1lI1 = string.gsub(d_0xll1lI1, '[^'..char_0xlI1IIl..'=]', '')
    local r_0xlIl1Il = {}
    for i_0xll1lII=1, #d_0xll1lI1, 4 do
        local c_0xlI1lll = b64_0xlll11l[d_0xll1lI1:sub(i_0xll1lII,i_0xll1lII)] or 0
        local c_0xlIIIlI = b64_0xlll11l[d_0xll1lI1:sub(i_0xll1lII+1,i_0xll1lII+1)] or 0
        local c_0xll1IlI, c_0xIIl1l1 = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xll1lI1:sub(i_0xll1lII+2,i_0xll1lII+2)
        if ch3 == "=" then has3 = false else c_0xll1IlI = b64_0xlll11l[ch3] or 0 end
        local ch4 = d_0xll1lI1:sub(i_0xll1lII+3,i_0xll1lII+3)
        if ch4 == "=" then has4 = false else c_0xIIl1l1 = b64_0xlll11l[ch4] or 0 end
        local b_0x1II1I1 = c_0xlI1lll * (2^18) + c_0xlIIIlI * (2^12) + c_0xll1IlI * (2^6) + c_0xIIl1l1
        local b_0xllII1I = math.floor(b_0x1II1I1 / (2^16)) % (2^8)
        local b_0xIll1l1 = math.floor(b_0x1II1I1 / (2^8)) % (2^8)
        local b_0xIIIlll = b_0x1II1I1 % (2^8)
        table.insert(r_0xlIl1Il, string.char(b_0xllII1I))
        if has3 then table.insert(r_0xlIl1Il, string.char(b_0xIll1l1)) end
        if has4 then table.insert(r_0xlIl1Il, string.char(b_0xIIIlll)) end
    end
    return table.concat(r_0xlIl1Il)
end


local function bxor_0x1IllII(a_0xII1Ill,b_0xIlIlI1)
    if bit32 then return bit32.bxor(a_0xII1Ill,b_0xIlIlI1) end
    local r_0xlIlIlI = 0
    for i_0xllIIII = 0, 7 do
        local x_0x1IIIII = a_0xII1Ill % 2
        local y_0x1llIII = b_0xIlIlI1 % 2
        if x_0x1IIIII ~= y_0x1llIII then r_0xlIlIlI = r_0xlIlIlI + (2^i_0xllIIII) end
        a_0xII1Ill = math.floor(a_0xII1Ill / 2)
        b_0xIlIlI1 = math.floor(b_0xIlIlI1 / 2)
    end
    return r_0xlIlIlI
end


local function bxor_str_0xl1lIIl(s_0xl11IIl, k_0xllIlI1)
    local r_0xIllIlI = {}
    for i_0xllI1II=1, #s_0xl11IIl do
        local b_0xllIlIl = string.byte(s_0xl11IIl, i_0xllI1II)
        local kb_0xl1111I = string.byte(k_0xllIlI1, (i_0xllI1II-1) % #k_0xllIlI1 + 1)
        r_0xIllIlI[i_0xllI1II] = string.char(bxor_0x1IllII(b_0xllIlIl, kb_0xl1111I))
    end
    return table.concat(r_0xIllIlI)
end


local function getkeys_0xIlII11()
    local seed = b64_0xlll11l.dec_0xIIllII("RHFvdWZhcFU=")
    local k1_enc = b64_0xlll11l.dec_0xIIllII("FDAaDR4GOTs=")
    local k2_enc = b64_0xlll11l.dec_0xIIllII("LgRcGxMPBBE=")
    return bxor_str_0xl1lIIl(k1_enc, seed), bxor_str_0xl1lIIl(k2_enc, seed)
end


local function cff_0xII1I1l(a_0xllI1II)
    local st_0xl1I1ll = 0
    local res_0xlllIll = a_0xllI1II
    while true do
        if st_0xl1I1ll == 0 then
            res_0xlllIll = res_0xlllIll + 1
            st_0xl1I1ll = 1
        elseif st_0xl1I1ll == 1 then
            res_0xlllIll = res_0xlllIll * 2
            st_0xl1I1ll = 2
        elseif st_0xl1I1ll == 2 then
            res_0xlllIll = res_0xlllIll - 3
            st_0xl1I1ll = 3
        else
            break
        end
    end
    return res_0xlllIll
end


local function chain_0xIII11I(x) return x*2 end
local function chain_0xllI1II(x) return chain_0xIII11I(x)+1 end


local d_0xl1l1ll = {
  {op=255, val="", is_enc=true},
}
local pc_0xII1ll1 = 1
local stk_0xIIlIlI = {}
stk_0xIIlIlI._jmp = nil


local disp_0x1ll1Il = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIlII11()

local state_0xIIlIl1 = 0
while true do
    if state_0xIIlIl1 == 0 then  -- FETCH
        if pc_0xII1ll1 > #d_0xl1l1ll then break end
        local inst = d_0xl1l1ll[pc_0xII1ll1]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlll11l.dec_0xIIllII(val)
            d = bxor_str_0xl1lIIl(d, k2)
            val = bxor_str_0xl1lIIl(d, k1)
